  apiKey: process.env.OPENAI_API_KEY!,
});

export const filesystemAgent = new Agent({
  name: 'filesystem-agent',
  instructions: 'You are a helpful agent that can interact with the filesystem.',
  model: openai('gpt-4o-mini'),
  tools: await mcp.getTools(),
});

import { filesystemAgent } from './agent';

async function main() {
  try {
    const result = await filesystemAgent.generate(
      "Write 'Hello from Mastra MCP' to /home/user/data/hello.txt"
    );
    console.log('Agent response:', result.text);
  } catch (error) {
    console.error('Error:', error);
    process.exit(1);
  }
}

main();

